question:
Tabelă de dispersie cu linear probing. Care afirmație este adevărată despre funcția de căutare?

Cod:
int functieStudent(struct Student* ht, int size, char* studName){
  char found = 0, i;
  for (i = 0; i < size && !found; i++)
    if (ht[i].name != NULL && strcmp(ht[i].name, studName)==0)
      found = 1;
  if (found == 1) return i;
  else return -1;
}

