question:
Care este afirmația corectă cu privire la funcția de mai jos?

Cod:
Student functionList(Node** head){
  Student s = {...};
  if (*head != NULL){
    s = (*head)->info;
    Node* tmp = *head;
    if ((*head)->next != (*head)){
      tmp->prev->next = tmp->next;
      tmp->next->prev = tmp->prev;
      *head = tmp->next;
    } else { *head = NULL; }
    free(tmp);
  }
  return s;
}

